// Helper: filter by category
export const getToolsByCategory = (category) =>
  ALL_TOOLS.filter(t => t.category === category)

// Helper: filter by subcategory
export const getToolsBySubcategory = (subcategory) =>
  ALL_TOOLS.filter(t => t.subcategory === subcategory)

// Helper: get P0 MVP tools
export const getMvpTools = () =>
  ALL_TOOLS.filter(t => t.priority === 'P0 MVP')

// Helper: search
export const searchTools = (query) => {
  const q = query.toLowerCase().trim()
  return ALL_TOOLS.filter(t =>
    t.id.toLowerCase().includes(q) ||
    t.name.toLowerCase().includes(q) ||
    t.category.toLowerCase().includes(q) ||
    t.subcategory.toLowerCase().includes(q) ||
    t.type.toLowerCase().includes(q) ||
    t.users.some(u => u.toLowerCase().includes(q))
  )
}

// Helper: get tool by ID
export const getToolById = (id) =>
  ALL_TOOLS.find(t => t.id === id)

// Demo tools for quick reference (first 12)
export const DEMO_TOOLS = ALL_TOOLS.slice(0, 12)
